		, #{updaterId}
		, #{updatedDt}
	)

mapper.update:
/** UsptAcdmcrDao.update */
update uspt_acdmcr
set
	bgnde			= #{bgnde}
	, endde			= #{endde}
	, schul_nm		= #{schulNm}
	, major			= #{major}
	, grdtn_div_cd	= #{grdtnDivCd}
	, updater_id	= #{updaterId}
	, updated_dt	= #{updatedDt}
where
	member_id = #{memberId}
	and acdmcr_id = #{acdmcrId}

